### Create Next.js API Endpoint for AI Comment Management

Source: https://github.com/ueberdosis/tiptap-docs/blob/main/src/content/content-ai/capabilities/ai-toolkit/advanced-guides/comments.mdx

This TypeScript code defines a Next.js API route (`/api/chat`) that leverages the Vercel AI SDK and an Anthropic model to process chat messages. It configures the Tiptap AI Toolkit's `toolDefinitions` to enable `getThreads` and `editThreads` for reading and editing comments, while optionally disabling `insertContent` and `applyPatch` to prevent the AI from making direct document modifications. The endpoint streams responses back to the client.

```typescript
// app/api/chat/route.ts
import { anthropic } from '@ai-sdk/anthropic'
import { toolDefinitions } from '@tiptap-pro/ai-toolkit-ai-sdk'
import { convertToModelMessages, streamText, UIMessage } from 'ai'

export async function POST(req: Request) {
  const { messages }: { messages: UIMessage[] } = await req.json()

  const result = streamText({
    model: anthropic('claude-haiku-4-5-20251001'),
    system: 'You are an assistant that can add comments to a rich text document.',
    messages: convertToModelMessages(messages),
    tools: toolDefinitions({
      tools: {
        // Enable the tools for reading and editing comments
        getThreads: true,
        editThreads: true,
        // (Optional) Prevent the AI from making changes to the document
        insertContent: false,
        applyPatch: false,
      },
    }),
  })

  return result.toUIMessageStreamResponse()
}
```

