### Initialize Tiptap Editor with AI Toolkit in React

Source: https://github.com/ueberdosis/tiptap-docs/blob/main/src/content/content-ai/capabilities/ai-toolkit/guides/inline-edits.mdx

This React component sets up a Tiptap editor using `useEditor` and integrates the `AiToolkit` extension. It displays the editor content and includes a basic button, preparing the UI for AI-powered text manipulation. It's a client-side component, indicated by `'use client'`. Dependencies include `@tiptap/react`, `@tiptap/starter-kit`, and `@tiptap-pro/ai-toolkit`.

```tsx
// app/page.tsx
'use client'

import { EditorContent, useEditor, useEditorState } from '@tiptap/react'
import StarterKit from '@tiptap/starter-kit'
import { useState } from 'react'
import { AiToolkit, getAiToolkit } from '@tiptap-pro/ai-toolkit'

export default function Page() {
  const editor = useEditor({
    immediatelyRender: false,
    extensions: [StarterKit, AiToolkit],
    content: `<p>Select some text and click the "Add emojis" button to add emojis to your selection.</p>`,
  })

  if (!editor) return null

  return (
    <>
      <EditorContent editor={editor} />
      <button>Add emojis</button>
    </>
  )
}
```
